import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Profile({ token, user, darkMode }) {
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({});
  const [activeTab, setActiveTab] = useState('profile'); // 'profile' or 'addresses'
  const [addresses, setAddresses] = useState([]);
  const [showAddressForm, setShowAddressForm] = useState(false);
  const [editingAddressId, setEditingAddressId] = useState(null);
  const [addressFormData, setAddressFormData] = useState({
    fullName: '',
    email: '',
    phone: '',
    address: '',
    city: '',
    province: '',
    postalCode: '',
    label: 'other',
    isDefault: false
  });

  const colors = {
    bg: darkMode ? '#0f0f0f' : '#fff',
    text: darkMode ? '#fff' : '#000',
    textLight: darkMode ? '#999' : '#999',
    border: darkMode ? '#333' : '#f0f0f0',
    imageBg: darkMode ? '#1a1a1a' : '#f9f9f9',
    errorBg: darkMode ? '#331111' : '#ffebee',
    errorText: darkMode ? '#ff6b6b' : '#d32f2f',
    successBg: darkMode ? '#1a3a1a' : '#f0f0f0',
    successText: darkMode ? '#66bb6a' : '#000'
  };

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const res = await axios.get('/api/users/profile', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setProfile(res.data);
      setFormData(res.data);
    } catch (err) {
      setError('Failed to load profile');
    } finally {
      setLoading(false);
    }
  };

  const handleSave = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.put('/api/users/profile', formData, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setProfile(res.data);
      setSuccess('Profile updated successfully!');
      setIsEditing(false);
      setTimeout(() => setSuccess(''), 2000);
    } catch (err) {
      setError('Failed to update profile');
    }
  };

  if (loading) return <div style={{ padding: '60px 50px', textAlign: 'center', fontFamily: 'Helvetica, Arial, sans-serif', backgroundColor: colors.bg, color: colors.text, transition: 'background-color 0.3s ease, color 0.3s ease' }}>Loading profile...</div>;
  if (error) return <div style={{ padding: '60px 50px', textAlign: 'center', fontFamily: 'Helvetica, Arial, sans-serif', color: colors.errorText, backgroundColor: colors.bg, transition: 'background-color 0.3s ease' }}>{error}</div>;

  const inputStyle = {
    width: '100%',
    padding: '12px 10px',
    border: `1px solid ${colors.border}`,
    fontSize: '13px',
    fontFamily: 'Helvetica, Arial, sans-serif',
    color: colors.text,
    backgroundColor: darkMode ? '#1a1a1a' : '#fff',
    boxSizing: 'border-box'
  };

  const labelStyle = {
    display: 'block',
    fontSize: '11px',
    fontWeight: '400',
    letterSpacing: '0.5px',
    textTransform: 'uppercase',
    color: colors.textLight,
    marginBottom: '8px'
  };

  return (
    <div style={{
      padding: '60px 50px',
      backgroundColor: colors.bg,
      fontFamily: 'Helvetica, Arial, sans-serif',
      transition: 'background-color 0.3s ease'
    }}>
      <h1 style={{
        fontSize: '28px',
        fontWeight: '300',
        letterSpacing: '1px',
        color: colors.text,
        margin: '0 0 40px 0',
        textTransform: 'uppercase'
      }}>
        MY ACCOUNT
      </h1>

      {success && (
        <div style={{
          padding: '12px',
          backgroundColor: colors.successBg,
          color: colors.successText,
          fontSize: '12px',
          marginBottom: '30px',
          letterSpacing: '0.5px'
        }}>
          {success}
        </div>
      )}

      {!isEditing ? (
        <div style={{ maxWidth: '500px' }}>
          <div style={{
            paddingBottom: '20px',
            marginBottom: '20px',
            borderBottom: `1px solid ${colors.border}`
          }}>
            <p style={{
              fontSize: '11px',
              fontWeight: '400',
              letterSpacing: '0.5px',
              textTransform: 'uppercase',
              color: colors.textLight,
              margin: '0 0 8px 0'
            }}>
              NAME
            </p>
            <p style={{
              fontSize: '13px',
              fontWeight: '300',
              color: colors.text,
              margin: '0'
            }}>
              {profile?.firstName && profile?.lastName
                ? `${profile.firstName} ${profile.lastName}`
                : profile?.name || 'Not provided'}
            </p>
          </div>

          <div style={{
            paddingBottom: '20px',
            marginBottom: '20px',
            borderBottom: `1px solid ${colors.border}`
          }}>
            <p style={{
              fontSize: '11px',
              fontWeight: '400',
              letterSpacing: '0.5px',
              textTransform: 'uppercase',
              color: colors.textLight,
              margin: '0 0 8px 0'
            }}>
              EMAIL
            </p>
            <p style={{
              fontSize: '13px',
              fontWeight: '300',
              color: colors.text,
              margin: '0'
            }}>
              {profile?.email}
            </p>
          </div>

          <div style={{
            paddingBottom: '20px',
            marginBottom: '20px',
            borderBottom: `1px solid ${colors.border}`
          }}>
            <p style={{
              fontSize: '11px',
              fontWeight: '400',
              letterSpacing: '0.5px',
              textTransform: 'uppercase',
              color: colors.textLight,
              margin: '0 0 8px 0'
            }}>
              PHONE
            </p>
            <p style={{
              fontSize: '13px',
              fontWeight: '300',
              color: colors.text,
              margin: '0'
            }}>
              {profile?.phone?.number || profile?.phone || 'Not provided'}
            </p>
          </div>

          <div style={{
            paddingBottom: '20px',
            marginBottom: '30px',
            borderBottom: `1px solid ${colors.border}`
          }}>
            <p style={{
              fontSize: '11px',
              fontWeight: '400',
              letterSpacing: '0.5px',
              textTransform: 'uppercase',
              color: colors.textLight,
              margin: '0 0 8px 0'
            }}>
              ADDRESS
            </p>
            <p style={{
              fontSize: '13px',
              fontWeight: '300',
              color: colors.text,
              margin: '0',
              lineHeight: '1.6'
            }}>
              {profile?.address || 'Not provided'}
            </p>
          </div>

          <button
            onClick={() => setIsEditing(true)}
            style={{
              padding: '15px 40px',
              backgroundColor: darkMode ? '#fff' : '#000',
              color: darkMode ? '#000' : '#fff',
              border: 'none',
              fontSize: '12px',
              fontFamily: 'Helvetica, Arial, sans-serif',
              fontWeight: '400',
              letterSpacing: '1px',
              textTransform: 'uppercase',
              cursor: 'pointer',
              transition: 'opacity 0.3s'
            }}
            onMouseEnter={(e) => e.target.style.opacity = '0.8'}
            onMouseLeave={(e) => e.target.style.opacity = '1'}
          >
            EDIT PROFILE
          </button>
        </div>
      ) : (
        <form onSubmit={handleSave} style={{ maxWidth: '500px' }}>
          <div style={{ marginBottom: '20px' }}>
            <label style={labelStyle}>First Name</label>
            <input
              type="text"
              value={formData.firstName || ''}
              onChange={(e) => setFormData({ ...formData, firstName: e.target.value })}
              style={inputStyle}
            />
          </div>

          <div style={{ marginBottom: '20px' }}>
            <label style={labelStyle}>Last Name</label>
            <input
              type="text"
              value={formData.lastName || ''}
              onChange={(e) => setFormData({ ...formData, lastName: e.target.value })}
              style={inputStyle}
            />
          </div>

          <div style={{ marginBottom: '20px' }}>
            <label style={labelStyle}>Email</label>
            <input
              type="email"
              value={formData.email || ''}
              disabled
              style={{
                ...inputStyle,
                backgroundColor: colors.imageBg,
                color: colors.textLight
              }}
            />
          </div>

          <div style={{ marginBottom: '20px' }}>
            <label style={labelStyle}>Phone</label>
            <input
              type="tel"
              value={formData.phone?.number || ''}
              onChange={(e) => setFormData({
                ...formData,
                phone: { ...formData.phone, number: e.target.value }
              })}
              style={inputStyle}
            />
          </div>

          <div style={{ marginBottom: '30px' }}>
            <label style={labelStyle}>Address</label>
            <textarea
              value={formData.address || ''}
              onChange={(e) => setFormData({ ...formData, address: e.target.value })}
              rows="4"
              style={{
                ...inputStyle,
                resize: 'vertical'
              }}
            />
          </div>

          <div style={{ display: 'flex', gap: '15px' }}>
            <button
              type="submit"
              style={{
                padding: '15px 40px',
                backgroundColor: darkMode ? '#fff' : '#000',
                color: darkMode ? '#000' : '#fff',
                border: 'none',
                fontSize: '12px',
                fontFamily: 'Helvetica, Arial, sans-serif',
                fontWeight: '400',
                letterSpacing: '1px',
                textTransform: 'uppercase',
                cursor: 'pointer',
                transition: 'opacity 0.3s'
              }}
              onMouseEnter={(e) => e.target.style.opacity = '0.8'}
              onMouseLeave={(e) => e.target.style.opacity = '1'}
            >
              SAVE CHANGES
            </button>
            <button
              type="button"
              onClick={() => setIsEditing(false)}
              style={{
                padding: '15px 40px',
                backgroundColor: colors.bg,
                color: colors.text,
                border: `1px solid ${colors.border}`,
                fontSize: '12px',
                fontFamily: 'Helvetica, Arial, sans-serif',
                fontWeight: '400',
                letterSpacing: '1px',
                textTransform: 'uppercase',
                cursor: 'pointer',
                transition: 'all 0.3s'
              }}
              onMouseEnter={(e) => {
                e.target.style.border = `1px solid ${colors.text}`;
              }}
              onMouseLeave={(e) => {
                e.target.style.border = `1px solid ${colors.border}`;
              }}
            >
              CANCEL
            </button>
          </div>
        </form>
      )}
    </div>
  );
}

export default Profile;
